function calculate({ rareEarthDependencyPercentage, manufacturingHubConcentrationIndex, geopoliticalRiskExposure, supplyChainDiversificationScore, inventoryBufferWeeks, earlyWarningSystemEffectiveness, regulatoryComplianceStability }) {

  // Input validation and clamping
  rareEarthDependencyPercentage = Math.max(0, Math.min(100, rareEarthDependencyPercentage));
  manufacturingHubConcentrationIndex = Math.max(1, Math.min(10, manufacturingHubConcentrationIndex));
  geopoliticalRiskExposure = Math.max(1, Math.min(10, geopoliticalRiskExposure));
  supplyChainDiversificationScore = Math.max(1, Math.min(10, supplyChainDiversificationScore));
  inventoryBufferWeeks = Math.max(0, inventoryBufferWeeks);
  earlyWarningSystemEffectiveness = Math.max(1, Math.min(10, earlyWarningSystemEffectiveness));
  regulatoryComplianceStability = Math.max(1, Math.min(10, regulatoryComplianceStability));

  // Define weights for each factor (sum of absolute weights should allow for a balanced score)
  const WEIGHTS = {
    rareEarthDependency: -0.30, // Higher dependency is a significant negative
    manufacturingConcentration: -0.25, // Higher concentration is a significant negative
    geopoliticalRisk: -0.20, // Higher risk is a strong negative
    diversification: 0.15, // Higher diversification is positive
    inventoryBuffer: 0.05, // More buffer is positive, scaled for impact
    earlyWarning: 0.05, // Effective warning systems are positive
    regulatoryStability: 0.05 // Stable environment is positive
  };

  // Convert inputs to a normalized scale (0-10 or 0-100) where higher means better resilience (or lower risk)
  // Risk factors (rare earth, manufacturing concentration, geopolitical risk) are inverted for consistency in scoring logic
  const normalizedRareEarthRisk = rareEarthDependencyPercentage / 100; // 0-1
  const normalizedManufacturingRisk = (manufacturingHubConcentrationIndex - 1) / 9; // 0-1
  const normalizedGeopoliticalRisk = (geopoliticalRiskExposure - 1) / 9; // 0-1

  // Resilience factors already scale positively with score
  const normalizedDiversification = (supplyChainDiversificationScore - 1) / 9; // 0-1
  const normalizedEarlyWarning = (earlyWarningSystemEffectiveness - 1) / 9; // 0-1
  const normalizedRegulatoryStability = (regulatoryComplianceStability - 1) / 9; // 0-1

  // Inventory buffer is a duration, let's cap its maximum positive impact for extremely long buffers
  const normalizedInventoryBuffer = Math.min(1, inventoryBufferWeeks / 16); // Max positive impact around 16 weeks

  // Calculate weighted contributions
  let scoreContribution = 0;

  scoreContribution += normalizedRareEarthRisk * WEIGHTS.rareEarthDependency;
  scoreContribution += normalizedManufacturingRisk * WEIGHTS.manufacturingConcentration;
  scoreContribution += normalizedGeopoliticalRisk * WEIGHTS.geopoliticalRisk;

  scoreContribution += normalizedDiversification * WEIGHTS.diversification;
  scoreContribution += normalizedInventoryBuffer * WEIGHTS.inventoryBuffer;
  scoreContribution += normalizedEarlyWarning * WEIGHTS.earlyWarning;
  scoreContribution += normalizedRegulatoryStability * WEIGHTS.regulatoryStability;

  // Normalize score to a 0-100 range
  // A baseline score (e.g., starting at 50) and then adjust based on contributions
  // The sum of absolute weights is 0.30 + 0.25 + 0.20 + 0.15 + 0.05 + 0.05 + 0.05 = 1.05
  // Max positive contribution: 0.15 + 0.05 + 0.05 + 0.05 = 0.3
  // Max negative contribution: -(0.30 + 0.25 + 0.20) = -0.75
  // Raw score range approximately -0.75 to 0.30

  // Let's re-normalize to a 0-1 scale where 1 is perfect resilience and 0 is extreme vulnerability
  // The maximum possible 'good' score (all resilience factors max, all risk factors min) is: 
  // (1 * 0.15) + (1 * 0.05) + (1 * 0.05) + (1 * 0.05) + (0 * -0.30) + (0 * -0.25) + (0 * -0.20) = 0.3
  // The maximum possible 'bad' score (all resilience factors min, all risk factors max) is: 
  // (0 * 0.15) + (0 * 0.05) + (0 * 0.05) + (0 * 0.05) + (1 * -0.30) + (1 * -0.25) + (1 * -0.20) = -0.75

  const minRawScore = -0.75; 
  const maxRawScore = 0.30;

  const scaledScore = ((scoreContribution - minRawScore) / (maxRawScore - minRawScore)) * 100;
  const finalScore = Math.round(Math.max(0, Math.min(100, scaledScore)));

  let riskCategory;
  if (finalScore >= 85) {
    riskCategory = 'Highly Resilient';
  } else if (finalScore >= 70) {
    riskCategory = 'Resilient';
  } else if (finalScore >= 50) {
    riskCategory = 'Moderate Risk';
  } else if (finalScore >= 30) {
    riskCategory = 'High Risk';
  } else {
    riskCategory = 'Critical Vulnerability';
  }

  return {
    resilienceScore: finalScore,
    riskCategory: riskCategory
  };
}
